function openModal(ls, q) {
  var data = window.MATRIX[ls][q];
  var action = window.ACTIONS[ls];
  var actionText = action ? (action.byQuality[q] || action.defaultAction) : "";
  document.getElementById("modal-title").innerHTML = esc(ls) + " × " + esc(q) + "级 — " + data.length + "人";
  var rows = "";
  for (var i = 0; i < data.length; i++) {
    var c = data[i];
    rows += "<tr><td style=\"white-space:nowrap;\">" + gradeTag(c.g) + "<strong>" + esc(c.n) + "</strong></td><td style=\"text-align:center;white-space:nowrap;font-size:11px;\">" + esc(c.c) + " · " + c.d + "d</td><td style=\"font-size:12px;\">" + (c.as ? \'⚠️ 售后待确认 — \' : \'\') + esc(c.st) + "</td><td style=\"color:var(--success);font-weight:600;font-size:12px;\">" + prioIcon(c.pr) + " " + esc(c.ac) + "</td></tr>";
  }
  document.getElementById("modal-body").innerHTML =
    '<div style="padding:8px 12px;margin-bottom:12px;background:var(--bg-tertiary);border-radius:6px;color:var(--accent);font-size:12px;">📋 标准动作参考：' + esc(actionText) + '</div>' +
    '<div style="max-height:55vh;overflow-y:auto;"><table><tr><th style="width:140px;">客户</th><th style="text-align:center;width:100px;">国家 · 静默</th><th>当前状态</th><th>行动方向</th></tr>' + rows + '</table></div>' +
    '<div style="margin-top:8px;font-size:10px;color:var(--text-tertiary);">💡 🔴今天必须 🟡今明可做 🟢正常等待 ⚪暂不行动 | ESC/点击遮罩关闭</div>';
  document.getElementById("modal-overlay").classList.add("show"); }
function closeModal() { document.getElementById("modal-overlay").classList.remove("show"); }
document.addEventListener("keydown", function(e) { if (e.key === "Escape") closeModal(); });

