const fs = require('fs');
const html = fs.readFileSync('dashboard_2026-05-13.html', 'utf8');

// Extract MATRIX data
const mStart = html.indexOf('window.MATRIX = {');
const mEnd = html.indexOf(';\nwindow.ACTIONS');
const matrixJson = html.substring(mStart + 17, mEnd);
const matrix = JSON.parse(matrixJson);

// Find specific customers
const targets = ['Christine Muwela', 'Asma Noor', 'fernande Pochette'];
for (const stage of Object.keys(matrix)) {
  for (const grade of Object.keys(matrix[stage])) {
    for (const c of matrix[stage][grade]) {
      if (targets.some(t => c.n.toLowerCase().includes(t.toLowerCase()))) {
        console.log(c.n, '-', stage, grade, '- d:', c.d, '- pr:', c.pr, '- ac:', c.ac.substring(0, 60));
      }
    }
  }
}
// Also check the prioIcon function in the HTML
const prioMatch = html.match(/function prioIcon[\s\S]*?\{[\s\S]*?\}/);
if (prioMatch) console.log('prioIcon:', prioMatch[0].substring(0, 150));

// Check action column CSS
const colorMatch = html.match(/color:var\(--success\)/);
console.log('--success still in HTML:', !!colorMatch);
const textPrimaryMatch = html.match(/color:var\(--text-primary\).*prioIcon/);
console.log('--text-primary in action column:', !!textPrimaryMatch);
"

