cd "d:\ClaudeWorkspace\08_客户跟进\Okki" && node -e "
const fs = require('fs');
const data = JSON.parse(fs.readFileSync('data/tm_conversations_full.json', 'utf8'));

// Search for Eddie by name
const convs = data.conversations;
const eddie = convs.find(c => c.name && c.name.toLowerCase().includes('eddie'));
if (eddie) {
  console.log('Found Eddie! CID:', eddie.cid);
  console.log('Keys:', Object.keys(eddie).join(', '));

  // Check for messages
  if (eddie.messages) {
    console.log('Messages count:', eddie.messages.length);
    eddie.messages.forEach((msg, i) => {
      console.log('--- Msg ' + i + ' ---');
      console.log('senderId:', msg.senderId);
      console.log('senderName:', msg.senderName);
      console.log('roleType:', msg.roleType);
      console.log('msgType:', msg.msgType);
      console.log('content:', (msg.content || '').substring(0, 300));
      console.log('sendTime:', msg.sendTime);
    });
  } else {
    console.log('No messages field');
    // Look for other message containers
    for (const [k, v] of Object.entries(eddie)) {
      if (Array.isArray(v)) console.log(k + ' is array, len=' + v.length);
    }
    console.log('First 1000 chars:', JSON.stringify(eddie).substring(0, 1000));
  }
} else {
  console.log('Eddie not found in conversations');
  // Show all unique names containing 'kil' or 'die'
  const matches = convs.filter(c => c.name && (c.name.toLowerCase().includes('kil') || c.name.toLowerCase().includes('eddie')));
  console.log('Partial matches:', matches.map(c => c.name));
}
"

